,["9063_Boundary"]={["bgDesc"]="板块中常见的部署造物，底座连接着能源脉络，通常处于休眠状态，启动时会对周边单位发起攻击。用途是防卫与警戒，大量布置在板块内各个区域交界处。",["type"]=3,["index"]=29,["name2"]="哨界碑",["id"]="9063_Boundary",["unlock_type"]=1,["bShowInAltas"]=true,["body"]=1,["skillDesc"]="哨界碑能对单个目标单位采取自律攻击",["race"]=3,["key"]="9063_Boundary",["unlock_id"]={1101}
