,["9072_Hypnos01"]={["bgDesc"]="哈迪斯在暗面收服的神秘造物，内部搭载的智能模拟系统赋予了其高度自学能力和独立思考能力。不但单体就拥有匹敌机神的性能，与『孪生机-塔纳托斯』协同作战时，战斗力更能得到飞跃性的提升。",["type"]=9,["index"]=48,["name2"]="修普诺斯",["id"]="9072_Hypnos01",["unlock_type"]=1,["bShowInAltas"]=true,["body"]=3,["skillDesc"]="藏身于虚空中的修普诺斯可夺去目标的意识，令其陷入无意识的“睡眠”",["race"]=3,["key"]="9072_Hypnos01",["unlock_id"]={1112}
